#include <stdio.h>

int main(void)
{
	int a,b,x=0,y=0,sum1,sum2,sumex=0;
	scanf("%d",&a);
	scanf("%d",&b);

	sum1=a+b;

	for(int i=1,j=1,k=1;a!=0||b!=0||sum1!=0;)
	{
		if(a%10!=0)  
		{
			x+=a%10*i;
			i*=10;	
		}

		if(b%10!=0)  
		{
			y+=b%10*j;
			j*=10;	
		}	

		if(sum1%10!=0)  
		{
			sumex+=sum1%10*k;
			k*=10;	
		}	

		a/=10;
		b/=10;
		sum1/=10;
	}

	sum2=x+y;
	//printf("%d %d %d",x,y,sumex);

	if(sumex==sum2) printf("YES");
	else printf("NO");

	return 0;
}

